package com.cognizant.order.controller;import com.cognizant.order.client.UserClient;import com.cognizant.order.model.CustomerOrder;import com.cognizant.order.repository.CustomerOrderRepository;import org.springframework.web.bind.annotation.*;import java.util.*;@RestController @RequestMapping("/orders") public class OrderController{private final CustomerOrderRepository repo;private final UserClient users;public OrderController(CustomerOrderRepository r,UserClient u){repo=r;users=u;}@PostMapping public CustomerOrder create(@RequestBody CustomerOrder o){users.user(o.getUserId());return repo.save(o);}@GetMapping("/{id}") public Map<String,Object> one(@PathVariable Long id){var o=repo.findById(id).orElseThrow();return Map.of("order",o,"user",users.user(o.getUserId()));}}